class Mutation {
  Mutation({
    required this.id,
    required this.key,
    required this.value,
    required this.basedOnRevision,
  });

  final String id;
  final String key;
  final String value;
  final int basedOnRevision;

  Mutation rebasedTo(int revision) => Mutation(
        id: id,
        key: key,
        value: value,
        basedOnRevision: revision,
      );
}

class Snapshot {
  Snapshot(this.revision, Map<String, String> values)
      : values = Map.unmodifiable(values);

  final int revision;
  final Map<String, String> values;
}

