import 'model.dart';
import 'protocol.dart';

enum DeliveryState { queued, inFlight }

class PendingMutation {
  PendingMutation(this.mutation);

  Mutation mutation;
  DeliveryState delivery = DeliveryState.queued;
  int? sentInSession;
}

class Outbox {
  final List<PendingMutation> _entries = <PendingMutation>[];

  void enqueue(Mutation mutation) {
    _entries.add(PendingMutation(mutation));
  }

  List<Mutation> openSession(int sessionId) {
    final send = <Mutation>[];
    for (final entry in _entries) {
      if (entry.delivery == DeliveryState.queued) {
        entry.delivery = DeliveryState.inFlight;
        entry.sentInSession = sessionId;
        send.add(entry.mutation);
      }
    }
    return List.unmodifiable(send);
  }

  void acknowledge(Ack ack) {
    _entries.removeWhere(
      (entry) =>
          entry.mutation.id == ack.mutationId &&
          entry.sentInSession == ack.sessionId,
    );
  }

  void rebaseAll(int revision) {
    for (final entry in _entries) {
      entry.mutation = entry.mutation.rebasedTo(revision);
    }
  }

  List<Mutation> get pending =>
      List.unmodifiable(_entries.map((entry) => entry.mutation));
}

