import 'model.dart';
import 'outbox.dart';
import 'protocol.dart';

class Replica {
  Replica({
    required int revision,
    required Map<String, String> values,
    Outbox? outbox,
  })  : revision = revision,
        _visible = Map.of(values),
        outbox = outbox ?? Outbox();

  int revision;
  Map<String, String> _visible;
  final Outbox outbox;

  Map<String, String> get visible => Map.unmodifiable(_visible);

  void edit(String id, String key, String value) {
    _visible[key] = value;
    outbox.enqueue(Mutation(
      id: id,
      key: key,
      value: value,
      basedOnRevision: revision,
    ));
  }

  void receiveSnapshot(Snapshot snapshot) {
    revision = snapshot.revision;
    _visible = Map.of(snapshot.values);
    outbox.rebaseAll(snapshot.revision);
  }

  List<Mutation> openSession(int sessionId) => outbox.openSession(sessionId);

  void acknowledge(Ack ack) {
    if (ack.revision > revision) {
      revision = ack.revision;
    }
    outbox.acknowledge(ack);
  }
}

