import '../lib/model.dart';
import '../lib/outbox.dart';
import '../lib/protocol.dart';
import '../lib/replica.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final queue = Outbox();
  queue.enqueue(Mutation(
    id: 'm-1',
    key: 'title',
    value: 'local',
    basedOnRevision: 3,
  ));
  final firstSend = queue.openSession(17);
  check(firstSend.length == 1, 'a fresh session sends queued work');
  check(firstSend.single.basedOnRevision == 3, 'the base revision is retained');
  queue.acknowledge(const Ack(
    sessionId: 17,
    mutationId: 'm-1',
    revision: 4,
  ));
  check(queue.pending.isEmpty, 'a matching acknowledgement clears the item');

  final replica = Replica(
    revision: 4,
    values: {'title': 'server', 'color': 'blue'},
  );
  replica.edit('m-2', 'title', 'draft');
  check(replica.visible['title'] == 'draft', 'local edits are optimistic');
  check(replica.visible['color'] == 'blue', 'unrelated fields remain visible');

  final cleanReplica = Replica(revision: 1, values: {'mode': 'old'});
  cleanReplica.receiveSnapshot(Snapshot(2, {'mode': 'new', 'peer': 'ready'}));
  check(cleanReplica.visible['mode'] == 'new', 'a clean replica accepts snapshots');
  check(cleanReplica.visible['peer'] == 'ready', 'remote additions are visible');
}
